import PressList from '../press-list/press-list.vue';
import PressEmpty from '../press-empty/press-empty.vue';


export default {
  components: {
    PressList,
    PressEmpty,
  },
  props: {
    rankMap: {
      type: Object,
      default: () => ({}),
    },
    myRankInfo: {
      type: Object,
      default: () => ({}),
    },
    immediateCheck: {
      type: Boolean,
      default: false,
    },
    finishedText: {
      type: String,
      default: '没有更多了',
    },
    finishedStyle: {
      type: String,
      default: '',
    },
    loadingStyle: {
      type: String,
      default: '',
    },
    loadingSize: {
      type: String,
      default: '20px',
    },
    rankTitle: {
      type: String,
      default: '主理人周榜',
    },
    rankNumPrefix: {
      type: String,
      default: '本周参赛人数：',
    },
    rankEmptyText: {
      type: String,
      default: '暂无主理人榜单',
    },
  },
  emits: [
    'clickRankItem',
    'focus',
    'loadMore',
    'update:loading',
  ],
  data() {
    return {
    };
  },
  computed: {
    rankList() {
      return this.rankMap.list || [];
    },
    curLoading: {
      get() {
        return this.rankMap.loading;
      },
      set(val) {
        this.$emit('update:loading', 'rankMap', val);
      },
    },
  },
  methods: {
    onLoadMore() {
      this.$emit('loadMore');
    },
    focus(item, index) {
      this.$emit('focus', item, index);
    },
    clickRankItem(item, index) {
      this.$emit('clickRankItem', item, index);
    },
  },
};

