import PressList from '../press-list/press-list.vue';
import PressEmpty from '../press-empty/press-empty.vue';


export default {
  components: {
    PressList,
    PressEmpty,
  },
  props: {
    curRankTab: {
      type: Number,
      default: 1,
    },
    followMap: {
      type: Object,
      default: () => ({}),
    },
    immediateCheck: {
      type: Boolean,
      default: false,
    },
    finishedText: {
      type: String,
      default: '没有更多了',
    },
    finishedStyle: {
      type: String,
      default: '',
    },
    loadingStyle: {
      type: String,
      default: '',
    },
    loadingSize: {
      type: String,
      default: '20px',
    },
  },
  emits: [
    'clickRankItem',
    'focus',
    'loadMore',
  ],
  data() {
    return {};
  },
  computed: {
    followList() {
      return this.followMap.list || [];
    },
    curLoading: {
      get() {
        return this.followMap.loading;
      },
      set(val) {
        this.$emit('update:loading', val);
      },
    },
  },
  methods: {
    friendList(item) {
      if (item && item.length > 3) {
        return item.slice(0, 3);
      }
      return item;
    },
    loadMore() {
      this.$emit('loadMore');
    },
    focus(item, index) {
      this.$emit('focus', item, index);
    },
    clickRankItem(item, index) {
      this.$emit('clickRankItem', item, index);
    },
    clickRankGames(item, index) {
      this.$emit('clickRankGames', item, index);
    },
  },
};

