import PressList from '../press-list/press-list.vue';
import PressEmpty from '../press-empty/press-empty.vue';
import PressTab from '../press-tab/press-tab';
import PressTabs from '../press-tabs/press-tabs';
import HorFollow from './follow.vue';


export default {
  components: {
    PressList,
    PressEmpty,
    PressTab,
    PressTabs,
    HorFollow,
  },
  props: {
    rankMap: {
      type: Object,
      default: () => ({}),
    },
    myFollow: {
      type: Object,
      default: () => ({}),
    },
    friendsFollow: {
      type: Object,
      default: () => ({}),
    },
    myRankInfo: {
      type: Object,
      default: () => ({}),
    },
    immediateCheck: {
      type: Boolean,
      default: false,
    },
    finishedText: {
      type: String,
      default: '没有更多了',
    },
    finishedStyle: {
      type: String,
      default: '',
    },
    loadingStyle: {
      type: String,
      default: '',
    },
    loadingSize: {
      type: String,
      default: '20px',
    },
    rankTitle: {
      type: String,
      default: '主理人周榜',
    },
    rankNumPrefix: {
      type: String,
      default: '本周参赛人数：',
    },
    rankEmptyText: {
      type: String,
      default: '暂无主理人榜单',
    },
    curRankTab: {
      type: Number,
      default: 0,
    },
  },
  emits: [
    'changeRankTab',
    'clickRankItem',
    'focus',
    'loadMore',
    'update:loading',
  ],
  data() {
    return {
      tabList: ['主理人月榜', '我关注的', '好友关注的'],
    };
  },
  computed: {
    rankList() {
      return this.rankMap.list || [];
    },
    curLoading: {
      get() {
        return this.rankMap.loading;
      },
      set(val) {
        this.$emit('update:loading', 'rankMap', val);
      },
    },
  },
  methods: {
    loadMore() {
      this.$emit('loadMore');
    },
    focus(item, index) {
      this.$emit('focus', item, index);
    },
    clickRankItem(item, index) {
      this.$emit('clickRankItem', item, index);
    },
    clickRankGames(item, index) {
      this.$emit('clickRankGames', item, index);
    },
    changeRankTab(tab) {
      this.$emit('changeRankTab', tab);
    },
    updateLoading(key, value) {
      this.$emit('update:loading', key, value);
    },
  },
};

